#include <stdio.h>
#include <math.h>

int main(void) {
    int n;
    double sum = 0.0;

    // Read integer n from input
    scanf("%d", &n);

    for (int i = 1; i <= n; ++i) {
        // Calculate numerator: 2i+1
        int numerator = 2 * i + 1;

        // Calculate denominator: i²-1
        double denominator = pow(i, 2) - 1;

        // Apply alternating signs
        if (i % 2 == 0) {
            sum -= numerator / denominator;
        } else {
            sum += numerator / denominator;
        }
    }

    // Output result with precision
    printf("%.3f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        // Print leading spaces to center the triangle
        for (int j = 0; j < n - i; j++) {
            printf(" ");
        }

        // Print digits for the current row
        for (int k = 0; k < i; k++) {
            printf("%d", i);
        }

        // Move to the next line
        printf("\n");
    }

    return 0;
}
